sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    // Per AAP Section 0.4.3 + Section 0.4.4 + Section 0.7.4:
    // Anonymous case-submission endpoint. The whitelisted-field discipline
    // (input fields restricted to subject, type, description, requester_name,
    // requester_email) plus the forced status='Draft' enforcement live in
    // the Script Include x_casemgmt.CasePortalService.submitCase(). This
    // handler is intentionally thin: only HTTP-layer concerns (status codes,
    // body shapes, payload extraction) live here.
    //
    // Per AAP Section 0.4.4 (verbatim, non-negotiable): the success
    // response includes the message text 'Your case has been submitted'.
    // The submission widget displays this text verbatim in its confirmation
    // panel; paraphrasing would break the AAP contract.

    // ----------------------------------------------------------------------
    // 1. Extract the JSON payload defensively.
    //
    //    request.body may be undefined (no body supplied - rare but
    //    possible if a malicious client sends POST with no Content-Type
    //    or empty body).
    //    request.body.data is the auto-parsed JSON object when the
    //    Content-Type is application/json (per <consumes>application/json
    //    </consumes> on this operation). It may be undefined if the body
    //    failed to parse.
    //    Pass null to the Script Include when either is missing - the
    //    Script Include's defensive type-check returns
    //    { error: 'Invalid payload.' } which this handler translates to
    //    HTTP 400.
    // ----------------------------------------------------------------------
    var payload = request.body && request.body.data ? request.body.data : null;

    // ----------------------------------------------------------------------
    // 2. Delegate to the Script Include. The Script Include is the single
    //    source of truth for:
    //      - The field whitelist (only subject, type, description,
    //        requester_name, requester_email accepted)
    //      - The status='Draft' force (regardless of payload contents)
    //      - The GlideRecord.insert() call against x_casemgmt_case
    //      - The post-insert re-query for the auto-generated number
    //
    //    Contract:
    //      - submitCase(payload) returns:
    //          * { error: '<message>' }   - validation/insert failure
    //          * { number: 'CASE0000001' } - success, auto-generated number
    //
    //    The Script Include is invoked via the scope-qualified API name
    //    `x_casemgmt.CasePortalService` (NOT by sys_id), which complies
    //    with AAP Section 0.7.2's no-hardcoded-sys_id constraint.
    // ----------------------------------------------------------------------
    var svc = new x_casemgmt.CasePortalService();
    var result = svc.submitCase(payload);

    // ----------------------------------------------------------------------
    // 3. Validation failure -> HTTP 400 Bad Request.
    //
    //    The Script Include returns { error: 'Invalid payload.' } when
    //    the payload is null/non-object/array, and
    //    { error: 'Submission failed.' } when GlideRecord.insert() rejects
    //    the row (typically a before-insert BR rejection or a missing
    //    mandatory field). Both surface as HTTP 400 to give the calling
    //    widget actionable feedback.
    //
    //    String() coercion on result.error defends against a future
    //    refactor that returns a non-string error value (e.g., an Error
    //    object); the JSON serializer would otherwise produce
    //    unpredictable output.
    // ----------------------------------------------------------------------
    if (result && result.error) {
        response.setStatus(400);
        response.setBody({ error: String(result.error) });
        return;
    }

    // ----------------------------------------------------------------------
    // 4. Defensive fallback -> HTTP 500 Internal Server Error.
    //
    //    This branch should NEVER trigger if the Script Include conforms
    //    to its contract (always returns either { number } or { error }).
    //    The fallback exists for production reliability:
    //      - If a future refactor breaks the Script Include's contract,
    //        the handler returns a clean 500 rather than serializing
    //        undefined or throwing an uncaught error.
    //      - The error message is intentionally generic ('Submission
    //        failed.') to avoid leaking implementation details to
    //        anonymous callers.
    // ----------------------------------------------------------------------
    if (!result || !result.number) {
        response.setStatus(500);
        response.setBody({ error: 'Submission failed.' });
        return;
    }

    // ----------------------------------------------------------------------
    // 5. Success -> HTTP 201 Created with { number, message }.
    //
    //    HTTP 201 (vs 200): REST convention - 201 indicates a NEW
    //    resource was created on the server. The submission widget can
    //    rely on this status code to distinguish successful creation
    //    from any other 2xx outcome.
    //
    //    Response body shape (exactly two keys, no others):
    //      {
    //        number:  '<auto-generated CASE0000001-format string>',
    //        message: 'Your case has been submitted'
    //      }
    //
    //    String(result.number) coercion defends against any future
    //    GlideElement-typed return value (the Script Include already
    //    coerces with String(savedGr.getValue('number')), but this
    //    handler-level coercion is defense-in-depth).
    //
    //    The verbatim message 'Your case has been submitted' matches AAP
    //    Section 0.4.4: "displays a confirmation panel showing the
    //    returned case number and a friendly 'Your case has been
    //    submitted' message". The widget displays this text verbatim
    //    in its confirmation panel.
    // ----------------------------------------------------------------------
    response.setStatus(201);
    response.setBody({
        number: String(result.number),
        message: 'Your case has been submitted'
    });
})(request, response);
